+                MermaidError::new("link directive missing url", span).with_expected(vec!["<url>"])
+            ));
+        }
+        url_idx = 2;
+    }
+    let target = normalize_ws(&tokens[0]);
+    let url = tokens
+        .get(url_idx)
+        .map(|s| s.trim().to_string())
+        .unwrap_or_default();
+    if url.is_empty() {
+        return Some(Err(
+            MermaidError::new("link directive missing url", span).with_expected(vec!["<url>"])
+        ));
+    }
+    let tooltip = if tokens.len() > url_idx + 1 {
+        Some(normalize_ws(&tokens[url_idx + 1..].join(" ")))
+    } else {
+        None
